#include "kernel_operator.h"

using namespace AscendC;

struct TallSkinnyMatrixMultiplicationCustomTilingData {
    int32_t M;
    int32_t N;
    int32_t K;
    int32_t baseM;
    int32_t baseN;
    int32_t baseK;
    int32_t blockDim;
};

class KernelTallSkinnyMatMul {
public:
    __aicore__ inline KernelTallSkinnyMatMul() {}

    __aicore__ inline void Init(GM_ADDR a, GM_ADDR b, GM_ADDR c, GM_ADDR workspace,
                                const TallSkinnyMatrixMultiplicationCustomTilingData& tilingData)
    {
        // Build TCubeTiling from the custom tiling data
        TCubeTiling tiling;
        tiling.set_M(tilingData.M);
        tiling.set_N(tilingData.N);
        tiling.set_K(tilingData.K);
        tiling.set_baseM(tilingData.baseM);
        tiling.set_baseN(tilingData.baseN);
        tiling.set_baseK(tilingData.baseK);
        tiling.set_aType(static_cast<int32_t>(ge::DT_FLOAT));
        tiling.set_bType(static_cast<int32_t>(ge::DT_FLOAT));
        tiling.set_cType(static_cast<int32_t>(ge::DT_FLOAT));
        tiling.set_biasType(static_cast<int32_t>(ge::DT_FLOAT));
        tiling.set_formatA(static_cast<int32_t>(ge::FORMAT_ND));
        tiling.set_formatB(static_cast<int32_t>(ge::FORMAT_ND));
        tiling.set_formatC(static_cast<int32_t>(ge::FORMAT_ND));
        tiling.set_hasBias(false);

        using A_TYPE = MatmulType<TPosition::GM, CubeFormat::ND, float, false, LayoutMode::NORMAL>;
        using B_TYPE = MatmulType<TPosition::GM, CubeFormat::ND, float, false, LayoutMode::NORMAL>;
        using C_TYPE = MatmulType<TPosition::GM, CubeFormat::ND, float, false, LayoutMode::NORMAL>;
        using BIAS_TYPE = MatmulType<TPosition::GM, CubeFormat::ND, float>;

        matmulObj.Init(a, b, nullptr, c, workspace, tiling);
    }

    __aicore__ inline void Process(AscendC::TPipe* pipe)
    {
        matmulObj.Process(pipe);
    }

    AscendC::Matmul<
        MatmulType<TPosition::GM, CubeFormat::ND, float, false, LayoutMode::NORMAL>,
        MatmulType<TPosition::GM, CubeFormat::ND, float, false, LayoutMode::NORMAL>,
        MatmulType<TPosition::GM, CubeFormat::ND, float, false, LayoutMode::NORMAL>,
        MatmulType<TPosition::GM, CubeFormat::ND, float>
    > matmulObj;
};

extern "C" __global__ __aicore__ void tall_skinny_matrix_multiplication_custom(
    GM_ADDR a, GM_ADDR b, GM_ADDR c, GM_ADDR workspace, GM_ADDR tilingGm)
{
    if (ASCEND_IS_AIV) {
        return;
    }

    // Manually copy tiling data from global memory (avoids missing generated header)
    TallSkinnyMatrixMultiplicationCustomTilingData tilingData;
    AscendC::Memcpy(&tilingData, tilingGm, sizeof(TallSkinnyMatrixMultiplicationCustomTilingData),
                    AscendC::MemcpyKind::GM2L);

    AscendC::TPipe pipe;
    KernelTallSkinnyMatMul kernel;
    kernel.Init(a, b, c, workspace, tilingData);
    REGIST_MATMUL_OBJ(&pipe, GetSysWorkSpacePtr(), kernel.matmulObj, &tilingData);
    kernel.Process(&pipe);
}
